import React from 'react';
import Card from "./Card";
function CardList({ repositories, onClick }) {
  return (
    <div className="cardList" style={{ display: 'flex', flexWrap: 'wrap', alignContent: 'flex-start' }}>
      {repositories.map((repository, index) => {
        return (
          <Card
            key={index}
            name={repository[0]}
            url={repository[1]}
          />
        );
      })}
    </div>
  );
}

